    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "instType": "SPOT", // SPOT, SWAP, etc
        //         "instId": "ETH-BTC", // BTC-USDT, BTC-USDT-SWAP, etc..
        //         "last": "0.07319",
        //         "lastSz": "0.044378", // base size for spot, or contracts amount for derivatives
        //         "askPx": "0.07322",
        //         "askSz": "4.2",
        //         "bidPx": "0.0732",
        //         "bidSz": "6.050058",
        //         "open24h": "0.07801",
        //         "high24h": "0.07975",
        //         "low24h": "0.06019",
        //         "volCcy24h": "11788.887619", // note, for derivatives this is base-amount
        //         "vol24h": "167493.829229",
        //         "ts": "1621440583784",
        //         "sodUtc0": "0.07872",
        //         "sodUtc8": "0.07345"
        //     }
        //
        //     {
        //          instId: 'LTC-USDT',
        //          idxPx: '65.74',
        //          open24h: '65.37',
        //          high24h: '66.15',
        //          low24h: '64.97',
        //          sodUtc0: '65.68',
        //          sodUtc8: '65.54',
        //          ts: '1728467346900'
        //     },
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object instType = this.safeString(ticker, "instType");
        Object marketType = null;
        if (Helpers.isTrue(!Helpers.isEqual(instType, null)))
        {
            marketType = ((Helpers.isTrue((Helpers.isEqual(instType, "SPOT"))))) ? "spot" : "swap";
        }
        Object timestamp = this.safeInteger(ticker, "ts");
        Object marketId = this.safeString(ticker, "instId");
        market = this.safeMarket(marketId, market, "-", marketType);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object last = this.safeString(ticker, "last");
        Object open = this.safeString(ticker, "open24h");
        Object spot = this.safeBool(market, "spot", false);
        Object quoteVolume = ((Helpers.isTrue(spot))) ? this.safeString(ticker, "volCcy24h") : null;
        Object baseVolume = this.safeString(ticker, "vol24h");
        Object high = this.safeString(ticker, "high24h");
        Object low = this.safeString(ticker, "low24h");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
            put( "high", high );
            put( "low", low );
            put( "bid", OkxCore.this.safeString(ticker, "bidPx") );
            put( "bidVolume", OkxCore.this.safeString(ticker, "bidSz") );
            put( "ask", OkxCore.this.safeString(ticker, "askPx") );
            put( "askVolume", OkxCore.this.safeString(ticker, "askSz") );
            put( "vwap", null );
            put( "open", open );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "markPrice", OkxCore.this.safeString(ticker, "markPx") );
            put( "indexPrice", OkxCore.this.safeString(ticker, "idxPx") );
            put( "info", ticker );
        }}, market);
    }

