    public Object parseLedgerEntryType(Object type)
    {
        Object types = new java.util.HashMap<String, Object>() {{
            put( "1", "transfer" );
            put( "2", "trade" );
            put( "3", "trade" );
            put( "4", "rebate" );
            put( "5", "trade" );
            put( "6", "transfer" );
            put( "7", "trade" );
            put( "8", "fee" );
            put( "9", "trade" );
            put( "10", "trade" );
            put( "11", "trade" );
        }};
        return this.safeString(types, type, type);
    }

    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        // privateGetAccountBills, privateGetAccountBillsArchive
        //
        //     {
        //         "bal": "0.0000819307998198",
        //         "balChg": "-664.2679586599999802",
        //         "billId": "310394313544966151",
        //         "ccy": "USDT",
        //         "fee": "0",
        //         "from": "",
        //         "instId": "LTC-USDT",
        //         "instType": "SPOT",
        //         "mgnMode": "cross",
        //         "notes": "",
        //         "ordId": "310394313519800320",
        //         "pnl": "0",
        //         "posBal": "0",
        //         "posBalChg": "0",
        //         "subType": "2",
        //         "sz": "664.26795866",
        //         "to": "",
        //         "ts": "1620275771196",
        //         "type": "2"
        //     }
        //
        // privateGetAssetBills
        //
        //     {
        //         "billId": "12344",
        //         "ccy": "BTC",
        //         "balChg": "2",
        //         "bal": "12",
        //         "type": "1",
        //         "ts": "1597026383085"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(item, "ccy");
        Object code = this.safeCurrencyCode(currencyId, currency);
        currency = this.safeCurrency(currencyId, currency);
        Object timestamp = this.safeInteger(item, "ts");
        Object feeCostString = this.safeString(item, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", OkxCore.this.parseNumber(Precise.stringNeg(finalFeeCostString)) );
                put( "currency", code );
            }};
        }
        Object marketId = this.safeString(item, "instId");
        Object symbol = this.safeSymbol(marketId, null, "-");
        final Object finalFee = fee;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", OkxCore.this.safeString(item, "billId") );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
            put( "account", null );
            put( "referenceId", OkxCore.this.safeString(item, "ordId") );
            put( "referenceAccount", null );
            put( "type", OkxCore.this.parseLedgerEntryType(OkxCore.this.safeString(item, "type")) );
            put( "currency", code );
            put( "symbol", symbol );
            put( "amount", OkxCore.this.safeNumber(item, "balChg") );
            put( "before", null );
            put( "after", OkxCore.this.safeNumber(item, "bal") );
            put( "status", "ok" );
            put( "fee", finalFee );
        }}, currency);
    }

    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        //
        //     {
        //         "addr": "okbtothemoon",
        //         "memo": "971668", // may be missing
        //         "tag":"52055", // may be missing
        //         "pmtId": "", // may be missing
        //         "ccy": "BTC",
        //         "to": "6", // 1 SPOT, 3 FUTURES, 6 FUNDING, 9 SWAP, 12 OPTION, 18 Unified account
        //         "selected": true
        //     }
        //
        //     {
        //         "ccy":"usdt-erc20",
        //         "to":"6",
        //         "addr":"0x696abb81974a8793352cbd33aadcf78eda3cfdfa",
        //         "selected":true
        //     }
        //
        //     {
        //        "chain": "ETH-OKExChain",
        //        "addrEx": { "comment": "6040348" }, // some currencies like TON may have this field,
        //        "ctAddr": "72315c",
        //        "ccy": "ETH",
        //        "to": "6",
        //        "addr": "0x1c9f2244d1ccaa060bd536827c18925db10db102",
        //        "selected": true
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object address = this.safeString(depositAddress, "addr");
        Object tag = this.safeStringN(depositAddress, new java.util.ArrayList<Object>(java.util.Arrays.asList("tag", "pmtId", "memo")));
        if (Helpers.isTrue(Helpers.isEqual(tag, null)))
        {
            Object addrEx = this.safeValue(depositAddress, "addrEx", new java.util.HashMap<String, Object>() {{}});
            tag = this.safeString(addrEx, "comment");
        }
        Object currencyId = this.safeString(depositAddress, "ccy");
        currency = this.safeCurrency(currencyId, currency);
        Object code = Helpers.GetValue(currency, "code");
        Object chain = this.safeString(depositAddress, "chain");
        Object networks = this.safeValue(currency, "networks", new java.util.HashMap<String, Object>() {{}});
        Object networksById = this.indexBy(networks, "id");
        Object networkData = ((Helpers.isTrue((Helpers.isEqual(chain, null))))) ? null : this.safeValue(networksById, chain);
        // inconsistent naming responses from exchange
        // with respect to network naming provided in currency info vs address chain-names and ids
        //
        // response from address endpoint:
        //      {
        //          "chain": "USDT-Polygon",
        //          "ctAddr": "",
        //          "ccy": "USDT",
        //          "to":"6" ,
        //          "addr": "0x1903441e386cc49d937f6302955b5feb4286dcfa",
        //          "selected": true
        //      }
        // network information from currency['networks'] field:
        // Polygon: {
        //        info: {
        //            canDep: false,
        //            canInternal: false,
        //            canWd: false,
        //            ccy: 'USDT',
        //            chain: 'USDT-Polygon-Bridge',
        //            mainNet: false,
        //            maxFee: '26.879528',
        //            minFee: '13.439764',
        //            minWd: '0.001',
        //            name: ''
        //        },
        //        id: 'USDT-Polygon-Bridge',
        //        network: 'Polygon',
        //        active: false,
        //        deposit: false,
        //        withdraw: false,
        //        fee: 13.439764,
        //        precision: undefined,
        //        limits: {
        //            withdraw: {
        //                min: 0.001,
        //                max: undefined
        //            }
        //        }
        //     },
        //
        if (Helpers.isTrue(Helpers.isEqual(chain, "USDT-Polygon")))
        {
            networkData = this.safeValue2(networksById, "USDT-Polygon-Bridge", "USDT-Polygon");
        }
        Object network = this.safeString(networkData, "network");
        Object networkCode = this.networkIdToCode(network, code);
        this.checkAddress(address);
        final Object finalTag = tag;
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", code );
            put( "network", networkCode );
            put( "address", address );
            put( "tag", finalTag );
        }};
    }

