    /**
     * @method
     * @name okx#fetchDepositAddress
     * @description fetch the deposit address for a currency associated with this account
     * @see https://www.okx.com/docs-v5/en/#funding-account-rest-api-get-deposit-address
     * @param {string} code unified currency code
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.network] the network name for the deposit address
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositAddress(Object code2, Object... optionalArgs)
    {
        final Object code3 = code2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object code = code3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object rawNetwork = this.safeString(parameters, "network"); // some networks are like "Dora Vota Mainnet"
            parameters = this.omit(parameters, "network");
            code = this.safeCurrencyCode(code);
            Object network = this.networkIdToCode(rawNetwork, code);
            Object response = (this.fetchDepositAddressesByNetwork(code, parameters)).join();
            if (Helpers.isTrue(!Helpers.isEqual(network, null)))
            {
                Object result = this.safeDict(response, network);
                if (Helpers.isTrue(Helpers.isEqual(result, null)))
                {
                    throw new InvalidAddress((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " fetchDepositAddress() cannot find "), network), " deposit address for "), code)) ;
                }
                return result;
            }
            Object codeNetwork = this.networkIdToCode(code, code);
            if (Helpers.isTrue(Helpers.inOp(response, codeNetwork)))
            {
                return Helpers.GetValue(response, codeNetwork);
            }
            // if the network is not specified, return the first address
            Object keys = Helpers.objectKeys(response);
            Object first = this.safeString(keys, 0, "");
            return this.safeDict(response, first);
        });

    }

    /**
     * @method
     * @name okx#withdraw
     * @description make a withdrawal
     * @see https://www.okx.com/docs-v5/en/#funding-account-rest-api-withdrawal
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address2, Object... optionalArgs)
    {
        final Object address3 = address2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object address = address3;
            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            this.checkAddress(address);
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object currency = this.currency(code);
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(tag, null))) && Helpers.isTrue((Helpers.isGreaterThan(((String)tag).length(), 0)))))
            {
                address = Helpers.add(Helpers.add(address, ":"), tag);
            }
            final Object finalAddress = address;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "ccy", Helpers.GetValue(currency, "id") );
                put( "toAddr", finalAddress );
                put( "dest", "4" );
                put( "amt", OkxCore.this.numberToString(amount) );
            }};
            Object network = this.safeString(parameters, "network"); // this line allows the user to specify either ERC20 or ETH
            if (Helpers.isTrue(!Helpers.isEqual(network, null)))
            {
                Object networks = this.safeDict(this.options, "networks", new java.util.HashMap<String, Object>() {{}});
                network = this.safeString(networks, ((String)network).toUpperCase(), network); // handle ETH>ERC20 alias
                Helpers.addElementToObject(request, "chain", Helpers.add(Helpers.add(Helpers.GetValue(currency, "id"), "-"), network));
                parameters = this.omit(parameters, "network");
            }
            Object fee = this.safeString(parameters, "fee");
            if (Helpers.isTrue(Helpers.isEqual(fee, null)))
            {
                Object currencies = (this.fetchCurrenciesAsync()).join();
                this.currencies = this.mapToSafeMap(this.deepExtend(this.currencies, currencies));
                Object targetNetwork = this.safeDict(Helpers.GetValue(currency, "networks"), this.networkIdToCode(network, Helpers.GetValue(currency, "code")), new java.util.HashMap<String, Object>() {{}});
                fee = this.safeString(targetNetwork, "fee");
                if (Helpers.isTrue(Helpers.isEqual(fee, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " withdraw() requires a \"fee\" string parameter, network transaction fee must be ≥ 0. Withdrawals to OKCoin or OKX are fee-free, please set \"0\". Withdrawing to external digital asset address requires network transaction fee.")) ;
                }
            }
            Helpers.addElementToObject(request, "fee", this.numberToString(fee)); // withdrawals to OKCoin or OKX are fee-free, please set 0
            Object query = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("fee")));
            Object response = (this.privatePostAssetWithdrawal(this.extend(request, query))).join();
            //
            //     {
            //         "code": "0",
            //         "msg": "",
            //         "data": [
            //             {
            //                 "amt": "0.1",
            //                 "wdId": "67485",
            //                 "ccy": "BTC"
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object transaction = this.safeDict(data, 0);
            return this.parseTransaction(transaction, currency);
        });

    }

