    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //     {
        //        "adl": "3",
        //        "availPos": "1",
        //        "avgPx": "34131.1",
        //        "cTime": "1627227626502",
        //        "ccy": "USDT",
        //        "deltaBS": "",
        //        "deltaPA": "",
        //        "gammaBS": "",
        //        "gammaPA": "",
        //        "imr": "170.66093041794787",
        //        "instId": "BTC-USDT-SWAP",
        //        "instType": "SWAP",
        //        "interest": "0",
        //        "last": "34134.4",
        //        "lever": "2",
        //        "liab": "",
        //        "liabCcy": "",
        //        "liqPx": "12608.959083877446",
        //        "markPx": "4786.459271773621",
        //        "margin": "",
        //        "mgnMode": "cross",
        //        "mgnRatio": "140.49930117599155",
        //        "mmr": "1.3652874433435829",
        //        "notionalUsd": "341.5130010779638",
        //        "optVal": "",
        //        "pos": "1",
        //        "posCcy": "",
        //        "posId": "339552508062380036",
        //        "posSide": "long",
        //        "thetaBS": "",
        //        "thetaPA": "",
        //        "tradeId": "98617799",
        //        "uTime": "1627227626502",
        //        "upl": "0.0108608358957281",
        //        "uplRatio": "0.0000636418743944",
        //        "vegaBS": "",
        //        "vegaPA": ""
        //    }
        // history
        //    {
        //        "cTime":"1708351230102",
        //        "ccy":"USDT",
        //        "closeAvgPx":"1.2567",
        //        "closeTotalPos":"40",
        //        "direction":"short",
        //        "fee":"-0.0351036",
        //        "fundingFee":"0",
        //        "instId":"SUSHI-USDT-SWAP",
        //        "instType":"SWAP",
        //        "lever":"10.0",
        //        "liqPenalty":"0",
        //        "mgnMode":"isolated",
        //        "openAvgPx":"1.2462",
        //        "openMaxPos":"40",
        //        "pnl":"-0.42",
        //        "pnlRatio":"-0.0912982667308618",
        //        "posId":"666159086676836352",
        //        "realizedPnl":"-0.4551036",
        //        "triggerPx":"",
        //        "type":"2",
        //        "uTime":"1708354805699",
        //        "uly":"SUSHI-USDT"
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "instId");
        market = this.safeMarket(marketId, market, null, "contract");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object pos = this.safeString(position, "pos"); // 'pos' field: One way mode: 0 if position is not open, 1 if open | Two way (hedge) mode: -1 if short, 1 if long, 0 if position is not open
        Object contractsAbs = Precise.stringAbs(pos);
        Object side = this.safeString2(position, "posSide", "direction");
        Object hedged = !Helpers.isEqual(side, "net");
        Object contracts = this.parseNumber(contractsAbs);
        if (Helpers.isTrue(Helpers.GetValue(market, "margin")))
        {
            // margin position
            if (Helpers.isTrue(Helpers.isEqual(side, "net")))
            {
                Object posCcy = this.safeString(position, "posCcy");
                Object parsedCurrency = this.safeCurrencyCode(posCcy);
                if (Helpers.isTrue(!Helpers.isEqual(parsedCurrency, null)))
                {
                    side = ((Helpers.isTrue((Helpers.isEqual(Helpers.GetValue(market, "base"), parsedCurrency))))) ? "long" : "short";
                }
            }
            if (Helpers.isTrue(Helpers.isEqual(side, null)))
            {
                side = this.safeString(position, "direction");
            }
        } else
        {
            if (Helpers.isTrue(!Helpers.isEqual(pos, null)))
            {
                if (Helpers.isTrue(Helpers.isEqual(side, "net")))
                {
                    if (Helpers.isTrue(Precise.stringGt(pos, "0")))
                    {
                        side = "long";
                    } else if (Helpers.isTrue(Precise.stringLt(pos, "0")))
                    {
                        side = "short";
                    } else
                    {
                        side = null;
                    }
                }
            }
        }
        Object contractSize = this.safeNumber(market, "contractSize");
        Object contractSizeString = this.numberToString(contractSize);
        Object markPriceString = this.safeString(position, "markPx");
        Object notionalString = this.safeString(position, "notionalUsd");
        if (Helpers.isTrue(Helpers.GetValue(market, "inverse")))
        {
            notionalString = Precise.stringDiv(Precise.stringMul(contractsAbs, contractSizeString), markPriceString);
        }
        Object notional = this.parseNumber(notionalString);
        Object marginMode = this.safeString(position, "mgnMode");
        Object initialMarginString = null;
        Object entryPriceString = this.safeString2(position, "avgPx", "openAvgPx");
        Object unrealizedPnlString = this.safeString(position, "upl");
        Object leverageString = this.safeString(position, "lever");
        Object initialMarginPercentage = null;
        Object collateralString = null;
        if (Helpers.isTrue(Helpers.isEqual(marginMode, "cross")))
        {
            initialMarginString = this.safeString(position, "imr");
            collateralString = Precise.stringAdd(initialMarginString, unrealizedPnlString);
        } else if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
        {
            initialMarginPercentage = Precise.stringDiv("1", leverageString);
            collateralString = this.safeString(position, "margin");
        }
        Object maintenanceMarginString = this.safeString(position, "mmr");
        Object maintenanceMargin = this.parseNumber(maintenanceMarginString);
        Object maintenanceMarginPercentageString = Precise.stringDiv(maintenanceMarginString, notionalString);
        if (Helpers.isTrue(Helpers.isEqual(initialMarginPercentage, null)))
        {
            initialMarginPercentage = this.parseNumber(Precise.stringDiv(initialMarginString, notionalString, 4));
        } else if (Helpers.isTrue(Helpers.isEqual(initialMarginString, null)))
        {
            if (Helpers.isTrue(Helpers.GetValue(market, "linear")))
            {
                initialMarginString = Precise.stringMul(initialMarginPercentage, notionalString);
            } else
            {
                initialMarginString = Precise.stringDiv(Precise.stringDiv(Precise.stringMul(contractsAbs, contractSizeString), entryPriceString), leverageString);
            }
        }
        Object rounder = "0.00005"; // round to closest 0.01%
        Object maintenanceMarginPercentage = this.parseNumber(Precise.stringDiv(Precise.stringAdd(maintenanceMarginPercentageString, rounder), "1", 4));
        Object liquidationPrice = this.safeNumber(position, "liqPx");
        Object percentageString = this.safeString(position, "uplRatio");
        Object percentage = this.parseNumber(Precise.stringMul(percentageString, "100"));
        Object timestamp = this.safeInteger(position, "cTime");
        Object marginRatio = this.parseNumber(Precise.stringDiv(maintenanceMarginString, collateralString, 4));
        final Object finalMarginMode = marginMode;
        final Object finalSide = side;
        final Object finalCollateralString = collateralString;
        final Object finalInitialMarginString = initialMarginString;
        final Object finalInitialMarginPercentage = initialMarginPercentage;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", OkxCore.this.safeString(position, "posId") );
            put( "symbol", symbol );
            put( "notional", notional );
            put( "marginMode", finalMarginMode );
            put( "liquidationPrice", liquidationPrice );
            put( "entryPrice", OkxCore.this.parseNumber(entryPriceString) );
            put( "unrealizedPnl", OkxCore.this.parseNumber(unrealizedPnlString) );
            put( "realizedPnl", OkxCore.this.safeNumber(position, "realizedPnl") );
            put( "percentage", percentage );
            put( "contracts", contracts );
            put( "contractSize", contractSize );
            put( "markPrice", OkxCore.this.parseNumber(markPriceString) );
            put( "lastPrice", OkxCore.this.safeNumber(position, "closeAvgPx") );
            put( "side", finalSide );
            put( "hedged", hedged );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
            put( "lastUpdateTimestamp", OkxCore.this.safeInteger(position, "uTime") );
            put( "maintenanceMargin", maintenanceMargin );
            put( "maintenanceMarginPercentage", maintenanceMarginPercentage );
            put( "collateral", OkxCore.this.parseNumber(finalCollateralString) );
            put( "initialMargin", OkxCore.this.parseNumber(finalInitialMarginString) );
            put( "initialMarginPercentage", OkxCore.this.parseNumber(finalInitialMarginPercentage) );
            put( "leverage", OkxCore.this.parseNumber(leverageString) );
            put( "marginRatio", marginRatio );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

    /**
     * @method
     * @name okx#transfer
     * @description transfer currency internally between wallets on the same account
     * @see https://www.okx.com/docs-v5/en/#rest-api-funding-funds-transfer
     * @param {string} code unified currency code
     * @param {float} amount amount to transfer
     * @param {string} fromAccount account to transfer from
     * @param {string} toAccount account to transfer to
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transfer(Object code, Object amount, Object fromAccount, Object toAccount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object currency = this.currency(code);
            Object accountsByType = this.safeDict(this.options, "accountsByType", new java.util.HashMap<String, Object>() {{}});
            Object fromId = this.safeString(accountsByType, fromAccount, fromAccount);
            Object toId = this.safeString(accountsByType, toAccount, toAccount);
            final Object finalFromId = fromId;
            final Object finalToId = toId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "ccy", Helpers.GetValue(currency, "id") );
                put( "amt", OkxCore.this.currencyToPrecision(code, amount) );
                put( "type", "0" );
                put( "from", finalFromId );
                put( "to", finalToId );
            }};
            if (Helpers.isTrue(Helpers.isEqual(fromId, "master")))
            {
                Helpers.addElementToObject(request, "type", "1");
                Helpers.addElementToObject(request, "subAcct", toId);
                Helpers.addElementToObject(request, "from", this.safeString(parameters, "from", "6"));
                Helpers.addElementToObject(request, "to", this.safeString(parameters, "to", "6"));
            } else if (Helpers.isTrue(Helpers.isEqual(toId, "master")))
            {
                Helpers.addElementToObject(request, "type", "2");
                Helpers.addElementToObject(request, "subAcct", fromId);
                Helpers.addElementToObject(request, "from", this.safeString(parameters, "from", "6"));
                Helpers.addElementToObject(request, "to", this.safeString(parameters, "to", "6"));
            }
            Object response = (this.privatePostAssetTransfer(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "0",
            //         "msg": "",
            //         "data": [
            //             {
            //                 "transId": "754147",
            //                 "ccy": "USDT",
            //                 "from": "6",
            //                 "amt": "0.1",
            //                 "to": "18"
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object rawTransfer = this.safeDict(data, 0, new java.util.HashMap<String, Object>() {{}});
            return this.parseTransfer(rawTransfer, currency);
        });

    }

    public Object parseTransfer(Object transfer, Object... optionalArgs)
    {
        //
        // transfer
        //
        //     {
        //         "transId": "754147",
        //         "ccy": "USDT",
        //         "from": "6",
        //         "amt": "0.1",
        //         "to": "18"
        //     }
        //
        // fetchTransfer
        //
        //     {
        //         "amt": "5",
        //         "ccy": "USDT",
        //         "from": "18",
        //         "instId": "",
        //         "state": "success",
        //         "subAcct": "",
        //         "to": "6",
        //         "toInstId": "",
        //         "transId": "464424732",
        //         "type": "0"
        //     }
        //
        // fetchTransfers
        //
        //     {
        //         "bal": "70.6874353780312913",
        //         "balChg": "-4.0000000000000000", // negative means "to funding", positive meand "from funding"
        //         "billId": "588900695232225299",
        //         "ccy": "USDT",
        //         "execType": "",
        //         "fee": "",
        //         "from": "18",
        //         "instId": "",
        //         "instType": "",
        //         "mgnMode": "",
        //         "notes": "To Funding Account",
        //         "ordId": "",
        //         "pnl": "",
        //         "posBal": "",
        //         "posBalChg": "",
        //         "price": "0",
        //         "subType": "12",
        //         "sz": "-4",
        //         "to": "6",
        //         "ts": "1686676866989",
        //         "type": "1"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString2(transfer, "transId", "billId");
        Object currencyId = this.safeString(transfer, "ccy");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object amount = this.safeNumber(transfer, "amt");
        Object fromAccountId = this.safeString(transfer, "from");
        Object toAccountId = this.safeString(transfer, "to");
        Object accountsById = this.safeDict(this.options, "accountsById", new java.util.HashMap<String, Object>() {{}});
        Object timestamp = this.safeInteger(transfer, "ts");
        Object balanceChange = this.safeString(transfer, "sz");
        if (Helpers.isTrue(!Helpers.isEqual(balanceChange, null)))
        {
            amount = this.parseNumber(Precise.stringAbs(balanceChange));
        }
        final Object finalAmount = amount;
        final Object finalFromAccountId = fromAccountId;
        final Object finalToAccountId = toAccountId;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transfer );
            put( "id", id );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
            put( "currency", code );
            put( "amount", finalAmount );
            put( "fromAccount", ((Helpers.isTrue((Helpers.isEqual(finalFromAccountId, null))))) ? null : OkxCore.this.safeString(accountsById, finalFromAccountId) );
            put( "toAccount", ((Helpers.isTrue((Helpers.isEqual(finalToAccountId, null))))) ? null : OkxCore.this.safeString(accountsById, finalToAccountId) );
            put( "status", OkxCore.this.parseTransferStatus(OkxCore.this.safeString(transfer, "state")) );
        }};
    }

    public Object parseTransferStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "success", "ok" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            return null;
        }
        return this.safeString(statuses, status, status);
    }

