    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object isArray = Helpers.isArray(parameters);
        Object request = Helpers.add(Helpers.add(Helpers.add("/api/", this.version), "/"), this.implodeParams(path, parameters));
        Object query = this.omit(parameters, this.extractParams(path));
        Object url = Helpers.add(this.implodeHostname(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "rest")), request);
        // const type = this.getPathAuthenticationType (path);
        if (Helpers.isTrue(Helpers.isEqual(api, "public")))
        {
            if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
            {
                url = Helpers.add(url, Helpers.add("?", this.urlencode(query)));
            }
        } else if (Helpers.isTrue(Helpers.isEqual(api, "private")))
        {
            this.checkRequiredCredentials();
            // inject id in implicit api call
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(method, "POST")) && Helpers.isTrue((Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(path, "trade/batch-orders")) || Helpers.isTrue(Helpers.isEqual(path, "trade/order-algo"))) || Helpers.isTrue(Helpers.isEqual(path, "trade/order"))))))
            {
                Object brokerId = this.safeString(this.options, "brokerId", "6b9ad766b55dBCDE");
                if (Helpers.isTrue(Helpers.isArray(parameters)))
                {
                    for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(parameters)); i++)
                    {
                        Object entry = Helpers.GetValue(parameters, i);
                        Object clientOrderId = this.safeString(entry, "clOrdId");
                        if (Helpers.isTrue(Helpers.isEqual(clientOrderId, null)))
                        {
                            Helpers.addElementToObject(entry, "clOrdId", Helpers.add(brokerId, this.uuid16()));
                            Helpers.addElementToObject(entry, "tag", brokerId);
                            Helpers.addElementToObject(parameters, i, entry);
                        }
                    }
                } else
                {
                    Object clientOrderId = this.safeString(parameters, "clOrdId");
                    if (Helpers.isTrue(Helpers.isEqual(clientOrderId, null)))
                    {
                        Helpers.addElementToObject(parameters, "clOrdId", Helpers.add(brokerId, this.uuid16()));
                        Helpers.addElementToObject(parameters, "tag", brokerId);
                    }
                }
            }
            Object timestamp = this.iso8601(this.nonce());
            final Object finalTimestamp = timestamp;
            headers = new java.util.HashMap<String, Object>() {{
                put( "OK-ACCESS-KEY", OkxCore.this.apiKey );
                put( "OK-ACCESS-PASSPHRASE", OkxCore.this.password );
                put( "OK-ACCESS-TIMESTAMP", finalTimestamp );
            }};
            Object auth = Helpers.add(Helpers.add(timestamp, method), request);
            if (Helpers.isTrue(Helpers.isEqual(method, "GET")))
            {
                if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
                {
                    Object urlencodedQuery = Helpers.add("?", this.urlencode(query));
                    url = Helpers.add(url, urlencodedQuery);
                    auth = Helpers.add(auth, urlencodedQuery);
                }
            } else
            {
                if (Helpers.isTrue(Helpers.isTrue(isArray) || Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query)))))
                {
                    body = this.json(query);
                    auth = Helpers.add(auth, body);
                }
                Helpers.addElementToObject(headers, "Content-Type", "application/json");
            }
            Object signature = this.hmac(this.encode(auth), this.encode(this.secret), sha256(), "base64");
            Helpers.addElementToObject(headers, "OK-ACCESS-SIGN", signature);
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    public Object parseFundingRate(Object contract, Object... optionalArgs)
    {
        //
        //    {
        //        "fundingRate": "0.00027815",
        //        "fundingTime": "1634256000000",
        //        "instId": "BTC-USD-SWAP",
        //        "instType": "SWAP",
        //        "nextFundingRate": "0.00017",
        //        "nextFundingTime": "1634284800000"
        //    }
        // ws
        //     {
        //        "fundingRate":"0.0001875391284828",
        //        "fundingTime":"1700726400000",
        //        "instId":"BTC-USD-SWAP",
        //        "instType":"SWAP",
        //        "method": "next_period",
        //        "maxFundingRate":"0.00375",
        //        "minFundingRate":"-0.00375",
        //        "nextFundingRate":"0.0002608059239328",
        //        "nextFundingTime":"1700755200000",
        //        "premium": "0.0001233824646391",
        //        "settFundingRate":"0.0001699799259033",
        //        "settState":"settled",
        //        "ts":"1700724675402"
        //     }
        //
        // in the response above nextFundingRate is actually two funding rates from now
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object nextFundingRateTimestamp = this.safeInteger(contract, "nextFundingTime");
        Object marketId = this.safeString(contract, "instId");
        Object symbol = this.safeSymbol(marketId, market);
        Object nextFundingRate = this.safeNumber(contract, "nextFundingRate");
        Object fundingTime = this.safeInteger(contract, "fundingTime");
        Object fundingTimeString = this.safeString(contract, "fundingTime");
        Object nextFundingTimeString = this.safeString(contract, "nextFundingTime");
        Object millisecondsInterval = Precise.stringSub(nextFundingTimeString, fundingTimeString);
        // https://www.okx.com/support/hc/en-us/articles/360053909272-Ⅸ-Introduction-to-perpetual-swap-funding-fee
        // > The current interest is 0.
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", symbol );
            put( "markPrice", null );
            put( "indexPrice", null );
            put( "interestRate", OkxCore.this.parseNumber("0") );
            put( "estimatedSettlePrice", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "fundingRate", OkxCore.this.safeNumber(contract, "fundingRate") );
            put( "fundingTimestamp", fundingTime );
            put( "fundingDatetime", OkxCore.this.iso8601(fundingTime) );
            put( "nextFundingRate", nextFundingRate );
            put( "nextFundingTimestamp", nextFundingRateTimestamp );
            put( "nextFundingDatetime", OkxCore.this.iso8601(nextFundingRateTimestamp) );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", OkxCore.this.parseFundingInterval(millisecondsInterval) );
        }};
    }

    public Object parseFundingInterval(Object interval)
    {
        Object intervals = new java.util.HashMap<String, Object>() {{
            put( "3600000", "1h" );
            put( "7200000", "2h" );
            put( "14400000", "4h" );
            put( "28800000", "8h" );
            put( "57600000", "16h" );
            put( "86400000", "24h" );
        }};
        return this.safeString(intervals, interval, interval);
    }

