    public java.util.concurrent.CompletableFuture<Object> modifyMarginHelper(Object symbol, Object amount, Object type, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object posSide = this.safeString(parameters, "posSide", "net");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("posSide")));
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instId", Helpers.GetValue(market, "id") );
                put( "amt", amount );
                put( "type", type );
                put( "posSide", posSide );
            }};
            Object response = (this.privatePostAccountPositionMarginBalance(this.extend(request, parameters))).join();
            //
            //     {
            //       "code": "0",
            //       "data": [
            //         {
            //           "amt": "0.01",
            //           "instId": "ETH-USD-SWAP",
            //           "posSide": "net",
            //           "type": "reduce"
            //         }
            //       ],
            //       "msg": ""
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object entry = this.safeDict(data, 0, new java.util.HashMap<String, Object>() {{}});
            Object errorCode = this.safeString(response, "code");
            final Object finalErrorCode = errorCode;
            return this.extend(this.parseMarginModification(entry, market), new java.util.HashMap<String, Object>() {{
                put( "status", ((Helpers.isTrue((Helpers.isEqual(finalErrorCode, "0"))))) ? "ok" : "failed" );
            }});
        });

    }

    public Object parseMarginModification(Object data, Object... optionalArgs)
    {
        //
        // addMargin/reduceMargin
        //
        //    {
        //        "amt": "0.01",
        //        "instId": "ETH-USD-SWAP",
        //        "posSide": "net",
        //        "type": "reduce"
        //    }
        //
        // fetchMarginAdjustmentHistory
        //
        //    {
        //        bal: '67621.4325135010619812',
        //        balChg: '-10.0000000000000000',
        //        billId: '691293628710342659',
        //        ccy: 'USDT',
        //        clOrdId: '',
        //        execType: '',
        //        fee: '0',
        //        fillFwdPx: '',
        //        fillIdxPx: '',
        //        fillMarkPx: '',
        //        fillMarkVol: '',
        //        fillPxUsd: '',
        //        fillPxVol: '',
        //        fillTime: '1711089244850',
        //        from: '',
        //        instId: 'XRP-USDT-SWAP',
        //        instType: 'SWAP',
        //        interest: '0',
        //        mgnMode: 'isolated',
        //        notes: '',
        //        ordId: '',
        //        pnl: '0',
        //        posBal: '73.12',
        //        posBalChg: '10.00',
        //        px: '',
        //        subType: '160',
        //        sz: '10',
        //        tag: '',
        //        to: '',
        //        tradeId: '0',
        //        ts: '1711089244699',
        //        type: '6'
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object amountRaw = this.safeString2(data, "amt", "posBalChg");
        Object typeRaw = this.safeString(data, "type");
        Object type = null;
        if (Helpers.isTrue(Helpers.isEqual(typeRaw, "6")))
        {
            type = ((Helpers.isTrue(Precise.stringGt(amountRaw, "0")))) ? "add" : "reduce";
        } else
        {
            type = typeRaw;
        }
        Object amount = Precise.stringAbs(amountRaw);
        Object marketId = this.safeString(data, "instId");
        Object responseMarket = this.safeMarket(marketId, market);
        Object code = ((Helpers.isTrue(Helpers.GetValue(responseMarket, "inverse")))) ? Helpers.GetValue(responseMarket, "base") : Helpers.GetValue(responseMarket, "quote");
        Object timestamp = this.safeInteger(data, "ts");
        final Object finalType = type;
        return new java.util.HashMap<String, Object>() {{
            put( "info", data );
            put( "symbol", Helpers.GetValue(responseMarket, "symbol") );
            put( "type", finalType );
            put( "marginMode", "isolated" );
            put( "amount", OkxCore.this.parseNumber(amount) );
            put( "code", code );
            put( "total", null );
            put( "status", null );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
        }};
    }

