    /**
     * @method
     * @name okx#fetchMarketLeverageTiers
     * @description retrieve information on the maximum leverage, and maintenance margin for trades of varying trade sizes for a single market
     * @see https://www.okx.com/docs-v5/en/#rest-api-public-data-get-position-tiers
     * @param {string} symbol unified market symbol
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.marginMode] 'cross' or 'isolated'
     * @returns {object} a [leverage tiers structure]{@link https://docs.ccxt.com/?id=leverage-tiers-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarketLeverageTiers(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object type = ((Helpers.isTrue(Helpers.GetValue(market, "spot")))) ? "MARGIN" : this.convertToInstrumentType(Helpers.GetValue(market, "type"));
            Object uly = this.safeString(Helpers.GetValue(market, "info"), "uly");
            if (!Helpers.isTrue(uly))
            {
                if (Helpers.isTrue(!Helpers.isEqual(type, "MARGIN")))
                {
                    throw new BadRequest((String)Helpers.add(Helpers.add(this.id, " fetchMarketLeverageTiers() cannot fetch leverage tiers for "), symbol)) ;
                }
            }
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("fetchMarketLeverageTiers", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(marginMode, null)))
            {
                marginMode = this.safeString(parameters, "tdMode", "cross"); // cross as default marginMode
            }
            final Object finalType = type;
            final Object finalMarginMode = marginMode;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instType", finalType );
                put( "tdMode", finalMarginMode );
                put( "uly", uly );
            }};
            if (Helpers.isTrue(Helpers.isEqual(type, "MARGIN")))
            {
                Helpers.addElementToObject(request, "instId", Helpers.GetValue(market, "id"));
            }
            Object response = (this.publicGetPublicPositionTiers(this.extend(request, parameters))).join();
            //
            //    {
            //        "code": "0",
            //        "data": [
            //            {
            //                "baseMaxLoan": "500",
            //                "imr": "0.1",
            //                "instId": "ETH-USDT",
            //                "maxLever": "10",
            //                "maxSz": "500",
            //                "minSz": "0",
            //                "mmr": "0.03",
            //                "optMgnFactor": "0",
            //                "quoteMaxLoan": "200000",
            //                "tier": "1",
            //                "uly": ""
            //            },
            //            ...
            //        ]
            //    }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseMarketLeverageTiers(data, market);
        });

    }

    public Object parseMarketLeverageTiers(Object info, Object... optionalArgs)
    {
        /**
        * @ignore
        * @method
        * @param {object} info Exchange response for 1 market
        * @param {object} market CCXT market
        */
        //
        //    [
        //        {
        //            "baseMaxLoan": "500",
        //            "imr": "0.1",
        //            "instId": "ETH-USDT",
        //            "maxLever": "10",
        //            "maxSz": "500",
        //            "minSz": "0",
        //            "mmr": "0.03",
        //            "optMgnFactor": "0",
        //            "quoteMaxLoan": "200000",
        //            "tier": "1",
        //            "uly": ""
        //        },
        //        ...
        //    ]
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object tiers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(info)); i++)
        {
            Object tier = Helpers.GetValue(info, i);
            Object marketId = this.safeString(tier, "instId");
            ((java.util.List<Object>)tiers).add(new java.util.HashMap<String, Object>() {{
                put( "tier", OkxCore.this.safeInteger(tier, "tier") );
                put( "symbol", OkxCore.this.safeSymbol(marketId, market) );
                put( "currency", OkxCore.this.safeString(market, "quote") );
                put( "minNotional", OkxCore.this.safeNumber(tier, "minSz") );
                put( "maxNotional", OkxCore.this.safeNumber(tier, "maxSz") );
                put( "maintenanceMarginRate", OkxCore.this.safeNumber(tier, "mmr") );
                put( "maxLeverage", OkxCore.this.safeNumber(tier, "maxLever") );
                put( "info", tier );
            }});
        }
        return tiers;
    }

    /**
     * @method
     * @name okx#fetchBorrowInterest
     * @description fetch the interest owed b the user for borrowing currency for margin trading
     * @see https://www.okx.com/docs-v5/en/#rest-api-account-get-interest-accrued-data
     * @param {string} code the unified currency code for the currency of the interest
     * @param {string} symbol the market symbol of an isolated margin market, if undefined, the interest for cross margin markets is returned
     * @param {int} [since] timestamp in ms of the earliest time to receive interest records for
     * @param {int} [limit] the number of [borrow interest structures]{@link https://docs.ccxt.com/?id=borrow-interest-structure} to retrieve
     * @param {object} [params] exchange specific parameters
     * @param {int} [params.type] Loan type 1 - VIP loans 2 - Market loans *Default is Market loans*
     * @param {string} [params.marginMode] 'cross' or 'isolated'
     * @returns {object[]} An list of [borrow interest structures]{@link https://docs.ccxt.com/?id=borrow-interest-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBorrowInterest(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object symbol = Helpers.getArg(optionalArgs, 1, null);
            Object since = Helpers.getArg(optionalArgs, 2, null);
            Object limit = Helpers.getArg(optionalArgs, 3, null);
            Object parameters = Helpers.getArg(optionalArgs, 4, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("fetchBorrowInterest", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(marginMode, null)))
            {
                marginMode = this.safeString(parameters, "mgnMode", "cross"); // cross as default marginMode
            }
            final Object finalMarginMode = marginMode;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "mgnMode", finalMarginMode );
            }};
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                Object currency = this.currency(code);
                Helpers.addElementToObject(request, "ccy", Helpers.GetValue(currency, "id"));
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "before", Helpers.subtract(since, 1));
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "instId", Helpers.GetValue(market, "id"));
            }
            Object response = (this.privateGetAccountInterestAccrued(this.extend(request, parameters))).join();
            //
            //    {
            //        "code": "0",
            //        "data": [
            //            {
            //                "ccy": "USDT",
            //                "instId": "",
            //                "interest": "0.0003960833333334",
            //                "interestRate": "0.0000040833333333",
            //                "liab": "97",
            //                "mgnMode": "",
            //                "ts": "1637312400000",
            //                "type": "1"
            //            },
            //            ...
            //        ],
            //        "msg": ""
            //    }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object interest = this.parseBorrowInterests(data);
            return this.filterByCurrencySinceLimit(interest, code, since, limit);
        });

    }

    public Object parseBorrowInterest(Object info, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object instId = this.safeString(info, "instId");
        if (Helpers.isTrue(!Helpers.isEqual(instId, null)))
        {
            market = this.safeMarket(instId, market);
        }
        Object timestamp = this.safeInteger(info, "ts");
        final Object finalMarket = market;
        return new java.util.HashMap<String, Object>() {{
            put( "info", info );
            put( "symbol", OkxCore.this.safeString(finalMarket, "symbol") );
            put( "currency", OkxCore.this.safeCurrencyCode(OkxCore.this.safeString(info, "ccy")) );
            put( "interest", OkxCore.this.safeNumber(info, "interest") );
            put( "interestRate", OkxCore.this.safeNumber(info, "interestRate") );
            put( "amountBorrowed", OkxCore.this.safeNumber(info, "liab") );
            put( "marginMode", OkxCore.this.safeString(info, "mgnMode") );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
        }};
    }

