    /**
     * @method
     * @name okx#fetchAllGreeks
     * @description fetches all option contracts greeks, financial metrics used to measure the factors that affect the price of an options contract
     * @see https://www.okx.com/docs-v5/en/#public-data-rest-api-get-option-market-data
     * @param {string[]} [symbols] unified symbols of the markets to fetch greeks for, all markets are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} params.uly Underlying, either uly or instFamily is required
     * @param {string} params.instFamily Instrument family, either uly or instFamily is required
     * @returns {object} a [greeks structure]{@link https://docs.ccxt.com/?id=greeks-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchAllGreeks(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object request = new java.util.HashMap<String, Object>() {{}};
            symbols = this.marketSymbols(symbols, null, true, true, true);
            Object symbolsLength = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                symbolsLength = Helpers.getArrayLength(symbols);
            }
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(symbols, null))) || Helpers.isTrue((!Helpers.isEqual(symbolsLength, 1)))))
            {
                Object uly = this.safeString(parameters, "uly");
                if (Helpers.isTrue(!Helpers.isEqual(uly, null)))
                {
                    Helpers.addElementToObject(request, "uly", uly);
                }
                Object instFamily = this.safeString(parameters, "instFamily");
                if (Helpers.isTrue(!Helpers.isEqual(instFamily, null)))
                {
                    Helpers.addElementToObject(request, "instFamily", instFamily);
                }
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(uly, null))) && Helpers.isTrue((Helpers.isEqual(instFamily, null)))))
                {
                    throw new BadRequest((String)Helpers.add(this.id, " fetchAllGreeks() requires either a uly or instFamily parameter")) ;
                }
            }
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                if (Helpers.isTrue(Helpers.isEqual(symbolsLength, 1)))
                {
                    market = this.market(Helpers.GetValue(symbols, 0));
                    Object marketId = this.safeString(market, "id", "");
                    Object optionParts = Helpers.split(marketId, "-");
                    Helpers.addElementToObject(request, "uly", Helpers.GetValue(Helpers.GetValue(market, "info"), "uly"));
                    Helpers.addElementToObject(request, "instFamily", Helpers.GetValue(Helpers.GetValue(market, "info"), "instFamily"));
                    Helpers.addElementToObject(request, "expTime", this.safeString(optionParts, 2));
                }
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("uly", "instFamily")));
            Object response = (this.publicGetPublicOptSummary(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "0",
            //         "data": [
            //             {
            //                 "askVol": "0",
            //                 "bidVol": "0",
            //                 "delta": "0.5105464486882039",
            //                 "deltaBS": "0.7325502184143025",
            //                 "fwdPx": "37675.80158694987186",
            //                 "gamma": "-0.13183515090501083",
            //                 "gammaBS": "0.000024139685826358558",
            //                 "instId": "BTC-USD-240329-32000-C",
            //                 "instType": "OPTION",
            //                 "lever": "4.504428015946619",
            //                 "markVol": "0.5916253554539876",
            //                 "realVol": "0",
            //                 "theta": "-0.0004202992014012855",
            //                 "thetaBS": "-18.52354631567909",
            //                 "ts": "1699586421976",
            //                 "uly": "BTC-USD",
            //                 "vega": "0.0020207455080045846",
            //                 "vegaBS": "74.44022302387287",
            //                 "volLv": "0.5948549730405797"
            //             },
            //         ],
            //         "msg": ""
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseAllGreeks(data, symbols);
        });

    }

    public Object parseGreeks(Object greeks, Object... optionalArgs)
    {
        //
        //     {
        //         "askVol": "0",
        //         "bidVol": "0",
        //         "delta": "0.5105464486882039",
        //         "deltaBS": "0.7325502184143025",
        //         "fwdPx": "37675.80158694987186",
        //         "gamma": "-0.13183515090501083",
        //         "gammaBS": "0.000024139685826358558",
        //         "instId": "BTC-USD-240329-32000-C",
        //         "instType": "OPTION",
        //         "lever": "4.504428015946619",
        //         "markVol": "0.5916253554539876",
        //         "realVol": "0",
        //         "theta": "-0.0004202992014012855",
        //         "thetaBS": "-18.52354631567909",
        //         "ts": "1699586421976",
        //         "uly": "BTC-USD",
        //         "vega": "0.0020207455080045846",
        //         "vegaBS": "74.44022302387287",
        //         "volLv": "0.5948549730405797"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(greeks, "ts");
        Object marketId = this.safeString(greeks, "instId");
        Object symbol = this.safeSymbol(marketId, market);
        return new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
            put( "delta", OkxCore.this.safeNumber(greeks, "delta") );
            put( "gamma", OkxCore.this.safeNumber(greeks, "gamma") );
            put( "theta", OkxCore.this.safeNumber(greeks, "theta") );
            put( "vega", OkxCore.this.safeNumber(greeks, "vega") );
            put( "rho", null );
            put( "bidSize", null );
            put( "askSize", null );
            put( "bidImpliedVolatility", OkxCore.this.safeNumber(greeks, "bidVol") );
            put( "askImpliedVolatility", OkxCore.this.safeNumber(greeks, "askVol") );
            put( "markImpliedVolatility", OkxCore.this.safeNumber(greeks, "markVol") );
            put( "bidPrice", null );
            put( "askPrice", null );
            put( "markPrice", null );
            put( "lastPrice", null );
            put( "underlyingPrice", null );
            put( "info", greeks );
        }};
    }

    /**
     * @method
     * @name okx#closePosition
     * @description closes open positions for a market
     * @see https://www.okx.com/docs-v5/en/#order-book-trading-trade-post-close-positions
     * @param {string} symbol Unified CCXT market symbol
     * @param {string} [side] 'buy' or 'sell', leave as undefined in net mode
     * @param {object} [params] extra parameters specific to the okx api endpoint
     * @param {string} [params.clientOrderId] a unique identifier for the order
     * @param {string} [params.marginMode] 'cross' or 'isolated', default is 'cross;
     * @param {string} [params.code] *required in the case of closing cross MARGIN position for Single-currency margin* margin currency
     *
     * EXCHANGE SPECIFIC PARAMETERS
     * @param {boolean} [params.autoCxl] whether any pending orders for closing out needs to be automatically canceled when close position via a market order. false or true, the default is false
     * @param {string} [params.tag] order tag a combination of case-sensitive alphanumerics, all numbers, or all letters of up to 16 characters
     * @returns {object[]} [A list of position structures]{@link https://docs.ccxt.com/?id=position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> closePosition(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object side = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object clientOrderId = this.safeString(parameters, "clientOrderId");
            Object code = this.safeString(parameters, "code");
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("closePosition", parameters, "cross");
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            final Object finalMarginMode = marginMode;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instId", Helpers.GetValue(market, "id") );
                put( "mgnMode", finalMarginMode );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(side, null)))
            {
                if (Helpers.isTrue((Helpers.isEqual(side, "buy"))))
                {
                    Helpers.addElementToObject(request, "posSide", "long");
                } else if (Helpers.isTrue(Helpers.isEqual(side, "sell")))
                {
                    Helpers.addElementToObject(request, "posSide", "short");
                } else
                {
                    Helpers.addElementToObject(request, "posSide", side);
                }
            }
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                Helpers.addElementToObject(request, "clOrdId", clientOrderId);
            }
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                Object currency = this.currency(code);
                Helpers.addElementToObject(request, "ccy", Helpers.GetValue(currency, "id"));
            }
            Object response = (this.privatePostTradeClosePosition(this.extend(request, parameters))).join();
            //
            //    {
            //        "code": "1",
            //        "data": [
            //            {
            //                "clOrdId":"e847386590ce4dBCe903bbc394dc88bf",
            //                "ordId":"",
            //                "sCode":"51000",
            //                "sMsg":"Parameter posSide error ",
            //                "tag":"e847386590ce4dBC"
            //            }
            //        ],
            //        "inTime": "1701877077101064",
            //        "msg": "All operations failed",
            //        "outTime": "1701877077102579"
            //    }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object order = this.safeDict(data, 0);
            return this.parseOrder(order, market);
        });

    }

