    public Object parseConversion(Object conversion, Object... optionalArgs)
    {
        //
        // fetchConvertQuote
        //
        //     {
        //         "baseCcy": "ETH",
        //         "baseSz": "0.01023052",
        //         "clQReqId": "",
        //         "cnvtPx": "2932.40104429",
        //         "origRfqSz": "30",
        //         "quoteCcy": "USDT",
        //         "quoteId": "quoterETH-USDT16461885104612381",
        //         "quoteSz": "30",
        //         "quoteTime": "1646188510461",
        //         "rfqSz": "30",
        //         "rfqSzCcy": "USDT",
        //         "side": "buy",
        //         "ttlMs": "10000"
        //     }
        //
        // createConvertTrade
        //
        //     {
        //         "baseCcy": "ETH",
        //         "clTReqId": "",
        //         "fillBaseSz": "0.01023052",
        //         "fillPx": "2932.40104429",
        //         "fillQuoteSz": "30",
        //         "instId": "ETH-USDT",
        //         "quoteCcy": "USDT",
        //         "quoteId": "quoterETH-USDT16461885104612381",
        //         "side": "buy",
        //         "state": "fullyFilled",
        //         "tradeId": "trader16461885203381437",
        //         "ts": "1646188520338"
        //     }
        //
        // fetchConvertTrade, fetchConvertTradeHistory
        //
        //     {
        //         "clTReqId": "",
        //         "instId": "ETH-USDT",
        //         "side": "buy",
        //         "fillPx": "2932.401044",
        //         "baseCcy": "ETH",
        //         "quoteCcy": "USDT",
        //         "fillBaseSz": "0.01023052",
        //         "state": "fullyFilled",
        //         "tradeId": "trader16461885203381437",
        //         "fillQuoteSz": "30",
        //         "ts": "1646188520000"
        //     }
        //
        Object fromCurrency = Helpers.getArg(optionalArgs, 0, null);
        Object toCurrency = Helpers.getArg(optionalArgs, 1, null);
        Object timestamp = this.safeInteger2(conversion, "quoteTime", "ts");
        Object fromCoin = this.safeString(conversion, "baseCcy");
        Object fromCode = this.safeCurrencyCode(fromCoin, fromCurrency);
        Object to = this.safeString(conversion, "quoteCcy");
        Object toCode = this.safeCurrencyCode(to, toCurrency);
        return new java.util.HashMap<String, Object>() {{
            put( "info", conversion );
            put( "timestamp", timestamp );
            put( "datetime", OkxCore.this.iso8601(timestamp) );
            put( "id", OkxCore.this.safeStringN(conversion, new java.util.ArrayList<Object>(java.util.Arrays.asList("clQReqId", "tradeId", "quoteId"))) );
            put( "fromCurrency", fromCode );
            put( "fromAmount", OkxCore.this.safeNumber2(conversion, "baseSz", "fillBaseSz") );
            put( "toCurrency", toCode );
            put( "toAmount", OkxCore.this.safeNumber2(conversion, "quoteSz", "fillQuoteSz") );
            put( "price", OkxCore.this.safeNumber2(conversion, "cnvtPx", "fillPx") );
            put( "fee", null );
        }};
    }

